public class TransactionManager {
    private static final String TAG = "TransactionManager";
    private static final String KEYSTORE_ALIAS = "BankingAppKey";
    private static final String PREFS_NAME = "secure_banking_prefs";
    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;
    
    private final Context context;
    private SharedPreferences securePrefs;
    private SecretKey encryptionKey;

    public TransactionManager(Context context) {
        this.context = context.getApplicationContext();
        initializeSecurity();
    }

    private void initializeSecurity() {
        try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                initializeKeyStore();
                initializeEncryptedPreferences();
            } else {
                // Fallback for older devices - use standard encrypted preferences
                securePrefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
            }
        } catch (Exception e) {
            Log.e(TAG, "Security initialization failed", e);
            throw new SecurityException("Failed to initialize secure storage");
        }
    }

    @RequiresApi(api = Build.VERSION_CODES.M)
    private void initializeKeyStore() throws GeneralSecurityException, IOException {
        KeyStore keyStore = KeyStore.getInstance("AndroidKeyStore");
        keyStore.load(null);

        if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
            KeyGenerator keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES, "AndroidKeyStore");
            
            KeyGenParameterSpec keyGenParameterSpec = new KeyGenParameterSpec.Builder(
                    KEYSTORE_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setKeySize(256)
                    .setUserAuthenticationRequired(false)
                    .build();
            
            keyGenerator.init(keyGenParameterSpec);
            encryptionKey = keyGenerator.generateKey();
        } else {
            encryptionKey = (SecretKey) keyStore.getKey(KEYSTORE_ALIAS, null);
        }
    }

    @RequiresApi(api = Build.VERSION_CODES.M)
    private void initializeEncryptedPreferences() throws GeneralSecurityException, IOException {
        MasterKey masterKey = new MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build();

        securePrefs = EncryptedSharedPreferences.create(
                context,
                PREFS_NAME,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        );
    }

    private String encrypt(String data) throws GeneralSecurityException {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
            cipher.init(Cipher.ENCRYPT_MODE, encryptionKey);
            
            byte[] iv = cipher.getIV();
            byte[] encrypted = cipher.doFinal(data.getBytes(StandardCharsets.UTF_8));
            
            byte[] combined = new byte[iv.length + encrypted.length];
            System.arraycopy(iv, 0, combined, 0, iv.length);
            System.arraycopy(encrypted, 0, combined, iv.length, encrypted.length);
            
            return Base64.encodeToString(combined, Base64.NO_WRAP);
        } else {
            // Simple encoding for older devices - not recommended for production
            return Base64.encodeToString(data.getBytes(StandardCharsets.UTF_8), Base64.NO_WRAP);
        }
    }

    private String decrypt(String encryptedData) throws GeneralSecurityException {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            byte[] combined = Base64.decode(encryptedData, Base64.NO_WRAP);
            
            byte[] iv = new byte[GCM_IV_LENGTH];
            byte[] encrypted = new byte[combined.length - GCM_IV_LENGTH];
            
            System.arraycopy(combined, 0, iv, 0, iv.length);
            System.arraycopy(combined, iv.length, encrypted, 0, encrypted.length);
            
            Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
            GCMParameterSpec spec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.DECRYPT_MODE, encryptionKey, spec);
            
            byte[] decrypted = cipher.doFinal(encrypted);
            return new String(decrypted, StandardCharsets.UTF_8);
        } else {
            byte[] decoded = Base64.decode(encryptedData, Base64.NO_WRAP);
            return new String(decoded, StandardCharsets.UTF_8);
        }
    }

    public BigDecimal getAccountBalance(String accountId) {
        try {
            String key = "balance_" + accountId;
            String encryptedBalance = securePrefs.getString(key, null);
            
            if (encryptedBalance == null) {
                return BigDecimal.ZERO;
            }
            
            String balanceStr = decrypt(encryptedBalance);
            return new BigDecimal(balanceStr);
        } catch (Exception e) {
            Log.e(TAG, "Error retrieving balance", e);
            return BigDecimal.ZERO;
        }
    }

    private void setAccountBalance(String accountId, BigDecimal balance) {
        try {
            String key = "balance_" + accountId;
            String encryptedBalance = encrypt(balance.toString());
            securePrefs.edit().putString(key, encryptedBalance).apply();
        } catch (Exception e) {
            Log.e(TAG, "Error saving balance", e);
            throw new SecurityException("Failed to save account balance");
        }
    }

    public synchronized TransactionResult processTransaction(Transaction transaction) {
        if (transaction == null) {
            return new TransactionResult(false, "Invalid transaction", null);
        }

        if (!validateTransaction(transaction)) {
            return new TransactionResult(false, "Transaction validation failed", null);
        }

        try {
            String fromAccount = transaction.getFromAccount();
            String toAccount = transaction.getToAccount();
            BigDecimal amount = transaction.getAmount();

            BigDecimal fromBalance = getAccountBalance(fromAccount);

            if (fromBalance.compareTo(amount) < 0) {
                return new TransactionResult(false, "Insufficient funds", null);
            }

            BigDecimal newFromBalance = fromBalance.subtract(amount);
            setAccountBalance(fromAccount, newFromBalance);

            BigDecimal toBalance = getAccountBalance(toAccount);
            BigDecimal newToBalance = toBalance.add(amount);
            setAccountBalance(toAccount, newToBalance);

            String transactionId = UUID.randomUUID().toString();
            saveTransactionRecord(transactionId, transaction);

            return new TransactionResult(true, "Transaction successful", transactionId);
        } catch (Exception e) {
            Log.e(TAG, "Transaction processing failed", e);
            return new TransactionResult(false, "Transaction failed: " + e.getMessage(), null);
        }
    }

    private boolean validateTransaction(Transaction transaction) {
        if (transaction.getFromAccount() == null || transaction.getFromAccount().isEmpty()) {
            return false;
        }
        if (transaction.getToAccount() == null || transaction.getToAccount().isEmpty()) {
            return false;
        }
        if (transaction.getAmount() == null || transaction.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            return false;
        }
        if (transaction.getFromAccount().equals(transaction.getToAccount())) {
            return false;
        }
        return true;
    }

    private void saveTransactionRecord(String transactionId, Transaction transaction) {
        try {
            String key = "transaction_" + transactionId;
            String transactionData = String.format("%s|%s|%s|%d",
                    transaction.getFromAccount(),
                    transaction.getToAccount(),
                    transaction.getAmount().toString(),
                    System.currentTimeMillis());
            
            String encrypted = encrypt(transactionData);
            securePrefs.edit().putString(key, encrypted).apply();
        } catch (Exception e) {
            Log.e(TAG, "Error saving transaction record", e);
        }
    }

    public List<TransactionRecord> getTransactionHistory(String accountId) {
        List<TransactionRecord> history = new ArrayList<>();
        try {
            for (String key : securePrefs.getAll().keySet()) {
                if (key.startsWith("transaction_")) {
                    String encrypted = securePrefs.getString(key, null);
                    if (encrypted != null) {
                        String decrypted = decrypt(encrypted);
                        String[] parts = decrypted.split("\\|");
                        
                        if (parts.length == 4 && 
                            (parts[0].equals(accountId) || parts[1].equals(accountId))) {
                            TransactionRecord record = new TransactionRecord(
                                    key.substring(12),
                                    parts[0],
                                    parts[1],
                                    new BigDecimal(parts[2]),
                                    Long.parseLong(parts[3])
                            );
                            history.add(record);
                        }
                    }
                }
            }
        } catch (Exception e) {
            Log.e(TAG, "Error retrieving transaction history", e);
        }
        return history;
    }

    public void clearAllData() {
        securePrefs.edit().clear().apply();
    }
}

