import android.content.Context;
import android.util.AttributeSet;
import android.view.LayoutInflater;
import android.widget.LinearLayout;
import android.widget.TextView;

import java.math.BigDecimal;
import java.text.NumberFormat;
import java.util.Currency;
import java.util.Locale;

public class AccountBalanceView extends LinearLayout {
    private TextView accountIdTextView;
    private TextView balanceTextView;
    private TransactionManager transactionManager;

    public AccountBalanceView(Context context) {
        super(context);
        init(context);
    }

    public AccountBalanceView(Context context, AttributeSet attrs) {
        super(context, attrs);
        init(context);
    }

    private void init(Context context) {
        setOrientation(VERTICAL);
        setPadding(16, 16, 16, 16);
        
        accountIdTextView = new TextView(context);
        accountIdTextView.setTextSize(14);
        addView(accountIdTextView);
        
        balanceTextView = new TextView(context);
        balanceTextView.setTextSize(24);
        addView(balanceTextView);
        
        transactionManager = new TransactionManager(context);
    }

    public void displayBalance(String accountId) {
        accountIdTextView.setText("Account: " + maskAccountId(accountId));
        
        BigDecimal balance = transactionManager.getAccountBalance(accountId);
        String formattedBalance = formatCurrency(balance);
        balanceTextView.setText(formattedBalance);
    }

    private String maskAccountId(String accountId) {
        if (accountId == null || accountId.length() < 4) {
            return "****";
        }
        return "****" + accountId.substring(accountId.length() - 4);
    }

    private String formatCurrency(BigDecimal amount) {
        NumberFormat formatter = NumberFormat.getCurrencyInstance(Locale.US);
        formatter.setCurrency(Currency.getInstance("USD"));
        return formatter.format(amount);
    }
}